'use client'

import { useState, useMemo } from 'react'
import Image from 'next/image'
import Link from 'next/link'
import Navbar from '@/components/layout/Navbar'
import Footer from '@/components/layout/Footer'
import { products, formatPrice, type Product } from '@/lib/products'

// ═══════════════════════════════════════════════════════════════════════════
// 1. COMPOSANTS UI (Cartes, Nav, etc.)
// ═══════════════════════════════════════════════════════════════════════════

function ProductCard({ product, size }: { product: Product; size: 'large' | 'small' }) {
    return (
        <Link
            href={`/product/${product.slug}`}
            className={`group relative block overflow-hidden rounded-2xl bg-white shadow-glass transition-all duration-500 hover:shadow-glass-xl ${size === 'large' ? 'aspect-[3/4]' : 'aspect-square'
                }`}
        >
            <Image
                src={product.images[0]}
                alt={product.title}
                fill
                className="object-cover transition-transform duration-700 group-hover:scale-105"
            />

            {/* Overlay */}
            <div className="absolute inset-0 bg-gradient-to-t from-petrol/70 via-petrol/0 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

            {/* Badges */}
            {product.new && (
                <span className="absolute top-4 left-4 px-3 py-1 bg-gold text-white text-xs font-mono uppercase rounded-full z-10">
                    Nouveau
                </span>
            )}
            <span className="absolute top-4 right-4 px-3 py-1 bg-white/80 backdrop-blur-sm text-petrol text-xs font-mono uppercase rounded-full z-10">
                {product.materialLabel}
            </span>

            {/* Info au hover */}
            <div className="absolute bottom-0 left-0 right-0 p-6 text-white translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                <h3 className="font-display text-xl md:text-2xl mb-1">{product.title}</h3>
                <p className="text-sm text-white/80 mb-2">{product.subtitle}</p>
                <p className="font-mono text-gold text-lg">{formatPrice(product.price)}</p>
            </div>
        </Link>
    )
}

// ═══════════════════════════════════════════════════════════════════════════
// 2. LOGIQUE CLIENT (Filtres & Grille)
// ═══════════════════════════════════════════════════════════════════════════

// Types de filtres disponibles (à adapter selon tes données réelles)
type FilterType = 'all' | 'wax' | 'cuir' | 'raphia' | 'textile';

export function CollectionFeed() {
    const [activeFilter, setActiveFilter] = useState<FilterType>('all');

    // Filtrage des produits optimisé avec useMemo
    const filteredProducts = useMemo(() => {
        if (activeFilter === 'all') return products;
        // Supposons que product.materialSlug ou product.category existe, sinon adapter la condition
        return products.filter(p => p.materialLabel?.toLowerCase().includes(activeFilter));
    }, [activeFilter]);

    // Logique de rendu de la grille asymétrique
    const renderGrid = () => {
        const elements: React.ReactNode[] = [];
        let i = 0;
        const items = filteredProducts;

        if (items.length === 0) {
            return (
                <div className="col-span-full py-20 text-center text-petrol/50 font-mono">
                    Aucun produit ne correspond à ce filtre.
                </div>
            );
        }

        while (i < items.length) {
            const isEvenGroup = Math.floor(i / 3) % 2 === 0;

            if (i + 2 < items.length) {
                // Pattern 1 Grand + 2 Petits
                elements.push(
                    <div key={`group-${i}`} className={`grid md:grid-cols-2 gap-6 ${isEvenGroup ? '' : 'md:grid-flow-col-dense'}`}>
                        <div className={`${isEvenGroup ? 'md:row-span-2' : 'md:row-span-2 md:col-start-2'}`}>
                            <ProductCard product={items[i]} size="large" />
                        </div>
                        <div className={isEvenGroup ? '' : 'md:col-start-1'}>
                            <ProductCard product={items[i + 1]} size="small" />
                        </div>
                        <div className={isEvenGroup ? '' : 'md:col-start-1'}>
                            <ProductCard product={items[i + 2]} size="small" />
                        </div>
                    </div>
                );
                i += 3;
            } else {
                // Reste (Grid simple)
                elements.push(
                    <div key={`remaining-${i}`} className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {items.slice(i).map((product) => (
                            <ProductCard key={product.id} product={product} size="small" />
                        ))}
                    </div>
                );
                break;
            }
        }
        return elements;
    };

    return (
        <>
            {/* Barre de Filtres */}
            <section className="pb-12 px-6 sticky top-20 z-40 bg-sand/95 backdrop-blur-sm py-4 transition-all">
                <div className="max-w-6xl mx-auto">
                    <div className="flex flex-wrap items-center justify-center gap-4">
                        <span className="font-mono text-sm uppercase tracking-wider text-petrol/50 mr-4 hidden md:inline">
                            Filtrer par :
                        </span>

                        <FilterButton
                            label="Tous"
                            isActive={activeFilter === 'all'}
                            onClick={() => setActiveFilter('all')}
                        />
                        <FilterButton
                            label="Wax"
                            colorClass="from-terracotta to-gold"
                            isActive={activeFilter === 'wax'}
                            onClick={() => setActiveFilter('wax')}
                        />
                        <FilterButton
                            label="Cuir"
                            colorClass="from-amber-800 to-amber-600"
                            isActive={activeFilter === 'cuir'}
                            onClick={() => setActiveFilter('cuir')}
                        />
                        <FilterButton
                            label="Raphia"
                            colorClass="from-amber-200 to-amber-100"
                            isActive={activeFilter === 'raphia'}
                            onClick={() => setActiveFilter('raphia')}
                        />
                    </div>
                </div>
            </section>

            {/* Grille Produits */}
            <section className="pb-32 px-6">
                <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-700">
                    {renderGrid()}
                </div>
            </section>
        </>
    )
}

// Composant Bouton Filtre helper
function FilterButton({ label, colorClass, isActive, onClick }: { label: string, colorClass?: string, isActive: boolean, onClick: () => void }) {
    return (
        <button
            onClick={onClick}
            className={`group flex items-center gap-2 px-6 py-3 font-mono text-sm uppercase tracking-wider rounded-full transition-all duration-300
                ${isActive
                    ? 'bg-petrol text-white shadow-lg scale-105'
                    : 'border-2 border-petrol/10 hover:border-terracotta text-petrol bg-white/50'
                }`}
        >
            {colorClass && (
                <span className={`w-4 h-4 rounded-full bg-gradient-to-br ${colorClass} ${isActive ? 'ring-2 ring-white' : ''}`}></span>
            )}
            {label}
        </button>
    )
}

// ═══════════════════════════════════════════════════════════════════════════
// 3. PAGE PRINCIPALE (Server Component)
// ═══════════════════════════════════════════════════════════════════════════

// Note: Dans Next.js App Router, ceci est le fichier `page.tsx`.
// Navbar et Footer devraient idéalement être dans `layout.tsx`, je les laisse ici pour l'exemple.

export default function CollectionPage() {
    return (
        <div className="min-h-screen bg-sand"> {/* Ajout bg-sand pour cohérence */}

            {/* Header Statique */}
            <Navbar />

            <section className="pt-32 pb-8 px-6">
                <div className="max-w-6xl mx-auto text-center">
                    <p className="font-mono text-sm uppercase tracking-[0.3em] text-terracotta mb-4">
                        Le Showroom
                    </p>
                    <h1 className="font-display text-5xl md:text-7xl mb-6 text-petrol">
                        Notre Collection
                    </h1>
                    <p className="text-lg text-petrol/70 max-w-2xl mx-auto">
                        Chaque étui est une pièce unique, confectionnée à la main.
                        Sélectionnez votre matière préférée et trouvez l&apos;étui qui vous ressemble.
                    </p>
                </div>
            </section>

            {/* Partie Interactive (Client) */}
            <CollectionFeed />

            {/* CTA Statique */}
            <CtaSection />

            <Footer />
        </div>
    )
}

// ═══════════════════════════════════════════════════════════════════════════
// 4. COMPOSANTS STATIQUES (Extraits pour la clarté)
// ═══════════════════════════════════════════════════════════════════════════

function Navbar() {
    return (
        <nav className="fixed top-0 left-0 right-0 z-50 px-6 py-4 md:px-12 bg-sand/80 backdrop-blur-md border-b border-petrol/5">
            <div className="flex items-center justify-between">
                <Link href="/" className="font-display text-2xl md:text-3xl text-petrol">
                    Glory<span className="text-gold">.</span>
                </Link>
                {/* ... (Reste de la nav identique) ... */}
                <div className="hidden md:flex items-center gap-8 font-mono text-sm uppercase tracking-wider text-petrol">
                    <Link href="/atelier" className="hover:text-terracotta transition-colors">L&apos;Atelier</Link>
                    <Link href="/collection" className="text-terracotta">Collection</Link>
                    <Link href="/pro" className="hover:text-terracotta transition-colors">Pro</Link>
                </div>
            </div>
        </nav>
    )
}

function CtaSection() {
    return (
        <section className="py-20 px-6 bg-petrol text-white text-center rounded-t-3xl mx-4 lg:mx-8">
            <h2 className="font-display text-3xl md:text-4xl mb-4">Un modèle vous plaît ?</h2>
            <p className="text-white/70 mb-8 max-w-md mx-auto">
                Commandez directement via WhatsApp.
            </p>
            <Link href="https://wa.me/22500000000" className="btn-gold inline-block px-8 py-3 bg-gold text-petrol font-bold uppercase tracking-wider rounded-sm hover:bg-white transition-colors">
                Commander via WhatsApp
            </Link>
        </section>
    )
}

function Footer() {
    return (
        <footer className="py-12 px-6 bg-petrol text-center text-white/50 border-t border-white/10">
            <p>© 2025 Blone. Fait avec ♥ à Abidjan</p>
        </footer>
    )
}